const claudeResponse = $input.first().json;
const text = claudeResponse.content[0].text;

// Haal categorie op
const categoryMatch = text.match(/CATEGORIE:\s*([^\n]+)/);
const category = categoryMatch ? categoryMatch[1].trim() : 'other';

// Haal concept op
const draftMatch = text.match(/CONCEPT:\s*([\s\S]+)/);
const draft = draftMatch ? draftMatch[1].trim() : text;

// Haal originele email data op
const originalEmail = $('✍️ Bouw Prompt').first().json;

return [{
  json: {
    category: category,
    draft: draft,
    originalFrom: originalEmail.originalFrom,
    originalSubject: originalEmail.originalSubject,
    originalText: originalEmail.originalText
  }
}];

